import os
import sqlite3
import shutil
from flask import Flask, render_template, request, session, redirect, url_for, g
from config import Config

app = Flask(__name__)
app.config.from_object(Config)

# Ensure DB is in /tmp for Read-Only FS compatibility
DB_PATH = '/tmp/veridian.db'
SEED_DB = '/app/seed.db'

if not os.path.exists(DB_PATH):
    shutil.copy(SEED_DB, DB_PATH)

def get_db():
    db = getattr(g, '_database', None)
    if db is None:
        db = g._database = sqlite3.connect(DB_PATH)
        db.row_factory = sqlite3.Row
    return db

@app.teardown_appcontext
def close_connection(exception):
    db = getattr(g, '_database', None)
    if db is not None:
        db.close()

def waf_filter(payload):
    # Realistic 'bad' filter that looks for keywords and spaces
    blacklist = ['OR', 'AND', '--', '#', ' ']
    for item in blacklist:
        if item in payload.upper():
            return False
    return True

@app.route('/')
def index():
    return render_template('index.html')

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')
        db = get_db()
        user = db.execute('SELECT * FROM users WHERE username = ? AND password = ?', (username, password)).fetchone()
        if user:
            session['user_id'] = user['id']
            session['username'] = user['username']
            return redirect(url_for('dashboard'))
        return render_template('login.html', error="Invalid credentials")
    return render_template('login.html')

@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('index'))

@app.route('/dashboard')
def dashboard():
    if 'user_id' not in session:
        return redirect(url_for('login'))
    return render_template('dashboard.html')

@app.route('/amenities')
def amenities():
    if 'user_id' not in session:
        return redirect(url_for('login'))
    search = request.args.get('search', '')
    db = get_db()
    # Safe red-herring: Parameterized query
    amenities_list = db.execute("SELECT name, description, status FROM amenities WHERE name LIKE ?", (f'%{search}%',)).fetchall()
    return render_template('amenities.html', amenities=amenities_list, search=search)

@app.route('/history')
def history():
    if 'user_id' not in session:
        return redirect(url_for('login'))

    search = request.args.get('search', '')
    error = None
    leases = []

    if search:
        if not waf_filter(search):
            error = "Security Filter: Prohibited characters or keywords detected. Our system has logged this attempt."
        else:
            db = get_db()
            try:
                # VULNERABLE: String formatting into query
                query = f"SELECT unit_number, start_date, end_date, monthly_rent FROM leases WHERE user_id = {session['user_id']} AND unit_number LIKE '%{search}%'"
                leases = db.execute(query).fetchall()
            except Exception as e:
                error = f"Database error: {str(e)}"
    else:
        db = get_db()
        leases = db.execute("SELECT unit_number, start_date, end_date, monthly_rent FROM leases WHERE user_id = ?", (session['user_id'],)).fetchall()

    return render_template('history.html', leases=leases, error=error, search=search)

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)

